use deadpool_redis::Pool;
use redis::AsyncCommands;

pub async fn check_redis(pool: &Pool) -> bool {
    let mut conn = match pool.get().await {
        Ok(c) => c,
        Err(_) => return false,
    };
    match conn.set_ex::<_, _, String>("health:ping", "pong", 10).await {
        Ok(_) => true,
        Err(_) => false,
    }
}

The check does a SET with expiry on every health probe, competing with real requests for pool connections. Under load this fails intermittently. The fix is to use a lightweight PING command and add a timeout.

