const SIZES = [2048, 1024, 512, 256, 128];

export async function generateThumbnails(inputPath: string) {
  const outputs = [];
  for (const size of SIZES) {
    const image = sharp(await fs.readFile(inputPath));
    const outputPath = inputPath.replace(/\.(\w+)$/, `_${size}.$1`);
    await image.resize(size, size, { fit: 'inside' }).toFile(outputPath);
    outputs.push(outputPath);
  }
  return outputs;
}

