import "database/sql"

func (s *JobStore) GetPending() ([]StoredJob, error) {
	rows, err := s.db.Query("SELECT id, payload FROM jobs WHERE status = 'pending'")
	if err != nil { return nil, err }
	defer rows.Close()
	var jobs []StoredJob
	for rows.Next() {
		var j StoredJob
		rows.Scan(&j.ID, &j.Payload)
		jobs = append(jobs, j)
	}
	return jobs, nil
}

